from py4godot.wrappers.wrappers import CPPGodotInstanceWrapper


class GodotInstance(py4godot_object.Object):
  r'''
		GodotInstance represents a running Godot instance that is controlled from an outside codebase, without a perpetual main loop. It is created by the C API `libgodot_create_godot_instance`. Only one may be created per process.
	'''

  @staticmethod
  def constructor():
    class_ = GodotInstance.construct_without_init()
    class_._ptr = constructor(388,0, ())
    return class_
  @staticmethod
  def new():
    class_ = GodotInstance.construct_without_init()
    class_._ptr = constructor(388,0, ())
    return class_
  def __init__(self):
    self._ptr =  CPPGodotInstanceWrapper()
    self.casted_from = None
    if c_utils.shouldCreateObject:
      self._ptr = constructor(388,0, ())


  def generate_wrapper(self):
    return CPPGodotInstanceWrapper()
  def init_signals(self):
    super().init_signals()

  @staticmethod
  def construct_without_init():
    cls = GodotInstance.__new__(GodotInstance)
    cls.shouldBeDeleted = True
    cls.casted_from = None
    cls.constructed_from_python = False
    cls.init_signals()
    return cls
  @staticmethod
  def get_type():
    return 'GodotInstance'

  def __del__(self):
    pass
  @staticmethod
  def cast(other:'Object'):
    assert other != None # Object to be casted must not be None
    cls = GodotInstance.construct_without_init()
    cls._ptr = CPPGodotInstanceWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls
  @staticmethod
  def cast_without_reference(other: 'Object'):
    assert other != None # Object to be casted must not be None
    cls = GodotInstance.construct_without_init()
    cls._ptr = CPPGodotInstanceWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls

  @functools.native_method
  def start(self) -> typing.Union[bool]:
    r'''
				Finishes this instance's startup sequence. Returns `true` on success.
			'''




    _ret = 0
    _ret = self._ptr.call_with_return(49,tuple([]))
    return _ret


  @functools.native_method
  def is_started(self) -> typing.Union[bool]:
    r'''
				Returns `true` if this instance has been fully started.
			'''




    _ret = 0
    _ret = self._ptr.call_with_return(50,tuple([]))
    return _ret


  @functools.native_method
  def iteration(self) -> typing.Union[bool]:
    r'''
				Runs a single iteration of the main loop. Returns `true` if the engine is attempting to quit.
			'''




    _ret = 0
    _ret = self._ptr.call_with_return(51,tuple([]))
    return _ret


  @functools.native_method
  def focus_in(self) -> None:
    r'''
				Notifies the instance that it is now in focus.
			'''




    self._ptr.call_with_return(52,tuple([]))

  @functools.native_method
  def focus_out(self) -> None:
    r'''
				Notifies the instance that it is now not in focus.
			'''




    self._ptr.call_with_return(53,tuple([]))

  @functools.native_method
  def pause(self) -> None:
    r'''
				Notifies the instance that it is going to be paused.
			'''




    self._ptr.call_with_return(54,tuple([]))

  @functools.native_method
  def resume(self) -> None:
    r'''
				Notifies the instance that it is being resumed.
			'''




    self._ptr.call_with_return(55,tuple([]))


